"use strict";parserFactory.register("novelmania.com.br",()=>new NovelmaniaParser);class NovelmaniaParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=[...e.querySelectorAll("ol.list-inline a")];for(let e of r)e.querySelector("small")?.remove();return r.map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div#chapter-content")}extractTitleImpl(e){return e.querySelector("h1")}extractAuthor(e){let r=e.querySelector("span.authors");return r?.querySelector("b")?.remove(),r?.textContent??super.extractAuthor(e)}extractLanguage(){return"pt"}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.novel-img")}getInformationEpubItemChildNodes(e){return[e.querySelector("div.text")]}}